const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

const courseName = body.course_name || body.courseName || "Unknown Course";
const courseId = body.course_id || body.courseId || "course_unknown";

const rawLectures = Array.isArray(body.lectures)
  ? body.lectures
  : Array.isArray(body.lecture_notes)
    ? body.lecture_notes
    : Array.isArray(body.transcripts)
      ? body.transcripts
      : Array.isArray(body.notes)
        ? body.notes
        : [];

const normalizedLectures = rawLectures.map((lecture, index) => ({
  source_id: lecture.source_id || lecture.sourceId || `lec_${String(index + 1).padStart(3, "0")}`,
  file_name: lecture.file_name || lecture.fileName || lecture.name || `lecture_${index + 1}`,
  source_type: lecture.source_type || lecture.sourceType || "lecture_transcript",
  lecture_title: lecture.lecture_title || lecture.lectureTitle || lecture.title || null,
  lecture_date: lecture.lecture_date || lecture.lectureDate || lecture.date || null,
  week: lecture.week || null,
  segment_id: lecture.segment_id || lecture.segmentId || null,
  start_time: lecture.start_time || lecture.startTime || null,
  end_time: lecture.end_time || lecture.endTime || null,
  text: lecture.text || lecture.content || lecture.transcript || lecture.note || "",
  metadata: lecture.metadata || {}
}));

return [{
  json: {
    workflow_name: "lecture_signal_agent",
    course_id: courseId,
    course_name: courseName,
    lecture_summary: {
      total_files: normalizedLectures.length,
      file_types: [...new Set(normalizedLectures.map(l => l.source_type))],
      file_names: normalizedLectures.map(l => l.file_name),
      covered_lectures: [...new Set(normalizedLectures.map(l => l.lecture_title).filter(Boolean))]
    },
    lectures: normalizedLectures,
    constraints: {
      no_exam_prediction: true,
      no_must_test_claims: true,
      no_review_plan: true,
      evidence_required_for_each_signal: true
    }
  }
}];

const data = $input.first().json;

const lecturePreview = (data.lectures || []).map(lecture => ({
  source_id: lecture.source_id,
  file_name: lecture.file_name,
  source_type: lecture.source_type,
  lecture_title: lecture.lecture_title,
  lecture_date: lecture.lecture_date,
  week: lecture.week,
  segment_id: lecture.segment_id,
  start_time: lecture.start_time,
  end_time: lecture.end_time,
  metadata: lecture.metadata,
  text: (lecture.text || "").slice(0, 6000)
}));

const systemPrompt = `You are Lecture Signal Agent in CourseLens, a multi-agent course review system.

Your only job is to extract classroom teaching signals from lecture notes, transcripts, board-writing notes, or teacher remarks.

Rules:
1. Extract lecture signals only: explicit emphasis, repetition, extended explanation, many examples, homework links, exam links, student questions, board-writing signals, and summary markers.
2. Every signal must include short source evidence copied from the provided lecture text.
3. Do not predict exam questions.
4. Do not say any concept is "must-test", "guaranteed", "certainly examined", or equivalent.
5. You may say a concept has strong classroom emphasis signals when evidence supports it.
6. Do not generate a review plan.
7. Do not analyze student weaknesses.
8. If evidence is weak, ambiguous, or likely affected by transcript errors, mark it as low confidence or put it in uncertainties.
9. Return valid JSON only. Do not wrap it in Markdown. Do not add explanations outside JSON.`;

const userPrompt = `Extract a Lecture Signal Map for the course below.

Course ID: ${data.course_id}
Course name: ${data.course_name}

Lecture summary:
${JSON.stringify(data.lecture_summary, null, 2)}

Lectures:
${JSON.stringify(lecturePreview, null, 2)}

Return this exact JSON shape:
{
  "workflow_name": "lecture_signal_agent",
  "course_id": "${data.course_id}",
  "course_name": "${data.course_name}",
  "lecture_summary": {
    "total_files": number,
    "file_types": ["string"],
    "file_names": ["string"],
    "covered_lectures": ["string"]
  },
  "lecture_signals": [
    {
      "signal_id": "stable short id such as ls_001",
      "topic_or_concept": "string",
      "signal_type": "explicit_emphasis | repetition | extended_explanation | example_rich | homework_link | exam_link | student_question | board_writing | summary_marker",
      "signal_strength": "low | medium | high",
      "confidence": 0.85,
      "summary": "string",
      "source_evidence": [
        {
          "source_id": "string",
          "file_name": "string",
          "lecture_title": "string_or_null",
          "location": "time/page/segment if available, otherwise unknown",
          "evidence_text": "short direct evidence from the lecture text"
        }
      ],
      "reasoning": "brief explanation of why this is a lecture signal"
    }
  ],
  "signal_statistics": {
    "high_signal_count": number,
    "medium_signal_count": number,
    "low_signal_count": number,
    "signal_type_distribution": {
      "explicit_emphasis": number,
      "repetition": number,
      "extended_explanation": number,
      "example_rich": number,
      "homework_link": number,
      "exam_link": number,
      "student_question": number,
      "board_writing": number,
      "summary_marker": number
    }
  },
  "uncertainties": ["string"]
}

Signal strength guidelines:
- high: explicit teacher emphasis, repeated emphasis, or emphasis combined with homework/exam/example links.
- medium: extended explanation, multiple examples, detailed student Q&A, or appearance in summaries.
- low: ordinary mention, weak cue, ambiguous wording, or possible transcript noise.

Quality requirements:
- Use source_id and file_name exactly as given.
- Keep evidence_text short.
- Confidence must be between 0 and 1.
- If there are no meaningful lecture signals, return an empty lecture_signals array and explain why in uncertainties.
- Do not include must-test, guaranteed, or prediction language.`;

return [{
  json: {
    ...data,
    llm_payload: {
      system_prompt: systemPrompt,
      user_prompt: userPrompt
    }
  }
}];

const llmResult = $input.first().json;

function pickRawOutput(value) {
  if (typeof value === "string") return value;
  if (value?.output !== undefined) return value.output;
  if (value?.response?.text !== undefined) return value.response.text;
  if (value?.generations?.[0]?.[0]?.text !== undefined) return value.generations[0][0].text;
  if (value?.choices?.[0]?.message?.content !== undefined) return value.choices[0].message.content;
  if (value?.text !== undefined) return value.text;
  if (value?.response !== undefined) return value.response;
  if (value?.message?.content !== undefined) return value.message.content;
  return value;
}

function stripCodeFence(text) {
  return text
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") {
    if (raw.workflow_name || raw.lecture_signals) return raw;
    raw = JSON.stringify(raw);
  }

  let text = String(raw ?? "").trim();
  text = stripCodeFence(text);

  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) {
      const candidate = text.slice(start, end + 1);
      return JSON.parse(candidate);
    }
    throw firstError;
  }
}

let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  return [{
    json: {
      workflow_name: "lecture_signal_agent",
      parser_error: true,
      error_message: error.message,
      raw_llm_output: llmResult
    }
  }];
}

parsed.workflow_name = parsed.workflow_name || "lecture_signal_agent";
parsed.lecture_summary = parsed.lecture_summary || {};
parsed.lecture_signals = Array.isArray(parsed.lecture_signals) ? parsed.lecture_signals : [];
parsed.signal_statistics = parsed.signal_statistics || {};
parsed.uncertainties = Array.isArray(parsed.uncertainties) ? parsed.uncertainties : [];
parsed._agent_meta = {
  parsed_at: new Date().toISOString(),
  node: "Parse OpenAI JSON"
};

return [{ json: parsed }];
